enum Message {
    Quit,
    MoveTo(i32, i32),
}

fn process_message(msg: &Message) -> &'static str {
    match msg {
        Message::Quit => "Quitting",
        Message::MoveTo(_, _) => "Moving",
    }
}

fn main() {
    let messages = vec![Message::Quit, Message::MoveTo(10, 20)];
    for m in messages {
        println!("{}", process_message(&m));
    }
}

